1:/**
2: * The Spider — rig execution engine apparatus.
3: *
4: * The Spider drives writ-to-completion by managing rigs: ordered pipelines
5: * of engine instances. Each crawl() call performs one unit of work:
6: *
7: *   collect > run > spawn   (priority order)
8: *
9: * collect — check running engines for terminal session results
10: * run     — execute the next pending engine (clockwork inline, quick → launch)
11: * spawn   — create a new rig for a ready writ with no existing rig
12: *
13: * CDC on the rigs book (Phase 1 cascade) transitions the associated writ
14: * when a rig reaches a terminal state (completed or failed).
15: *
16: * See: docs/architecture/apparatus/spider.md
17: */
19:import type { Plugin, StartupContext } from '@shardworks/nexus-core';
20:import { guild, generateId } from '@shardworks/nexus-core';
21:import type { StacksApi, Book, ReadOnlyBook, WhereClause } from '@shardworks/stacks-apparatus';
22:import type { ClerkApi, WritDoc } from '@shardworks/clerk-apparatus';
23:import type { FabricatorApi } from '@shardworks/fabricator-apparatus';
24:import type { SessionDoc } from '@shardworks/animator-apparatus';
26:import type {
27:  RigDoc,
28:  RigFilters,
29:  EngineInstance,
30:  SpiderApi,
31:  CrawlResult,
32:  SpiderConfig,
33:} from './types.ts';
35:import {
36:  draftEngine,
37:  implementEngine,
38:  reviewEngine,
39:  reviseEngine,
40:  sealEngine,
41:} from './engines/index.ts';
43:import { crawlOneTool, crawlContinualTool, rigShowTool, rigListTool, rigForWritTool } from './tools/index.ts';
45:// ── Helpers ────────────────────────────────────────────────────────────
47:/**
48: * Check whether a value is JSON-serializable.
49: * Non-serializable yields cause engine failure — the Stacks cannot store them.
50: */
51:function isJsonSerializable(value: unknown): boolean {
52:  try {
53:    JSON.stringify(value);
54:    return true;
55:  } catch {
56:    return false;
57:  }
58:}
60:/**
61: * Build the upstream yields map for a rig: all completed engine yields
62: * keyed by engine id. Passed as context.upstream to the engine's run().
63: */
64:function buildUpstreamMap(rig: RigDoc): Record<string, unknown> {
65:  const upstream: Record<string, unknown> = {};
66:  for (const engine of rig.engines) {
67:    if (engine.status === 'completed' && engine.yields !== undefined) {
68:      upstream[engine.id] = engine.yields;
69:    }
70:  }
71:  return upstream;
72:}
74:/**
75: * Find the first pending engine whose entire upstream is completed.
76: * Returns null if no runnable engine exists.
77: */
78:function findRunnableEngine(rig: RigDoc): EngineInstance | null {
79:  for (const engine of rig.engines) {
80:    if (engine.status !== 'pending') continue;
81:    const allUpstreamDone = engine.upstream.every((upstreamId) => {
82:      const dep = rig.engines.find((e) => e.id === upstreamId);
83:      return dep?.status === 'completed';
84:    });
85:    if (allUpstreamDone) return engine;
86:  }
87:  return null;
88:}
90:/**
91: * Produce the five-engine static pipeline for a writ.
92: * Each engine receives only the givens it needs.
93: * Upstream yields arrive via context.upstream at run time.
94: */
95:function buildStaticEngines(writ: WritDoc, config: SpiderConfig): EngineInstance[] {
96:  const role = config.role ?? 'artificer';
97:  const reviewGivens: Record<string, unknown> = {
98:    writ,
99:    role: 'reviewer',
100:    ...(config.buildCommand !== undefined ? { buildCommand: config.buildCommand } : {}),
101:    ...(config.testCommand !== undefined ? { testCommand: config.testCommand } : {}),
102:  };
104:  return [
105:    { id: 'draft',     designId: 'draft',     status: 'pending', upstream: [],           givensSpec: { writ } },
106:    { id: 'implement', designId: 'implement', status: 'pending', upstream: ['draft'],     givensSpec: { writ, role } },
107:    { id: 'review',    designId: 'review',    status: 'pending', upstream: ['implement'], givensSpec: reviewGivens },
108:    { id: 'revise',    designId: 'revise',    status: 'pending', upstream: ['review'],    givensSpec: { writ, role } },
109:    { id: 'seal',      designId: 'seal',      status: 'pending', upstream: ['revise'],    givensSpec: {} },
110:  ];
111:}
113:// ── Apparatus factory ──────────────────────────────────────────────────
115:export function createSpider(): Plugin {
116:  let rigsBook: Book<RigDoc>;
117:  let sessionsBook: ReadOnlyBook<SessionDoc>;
118:  let writsBook: ReadOnlyBook<WritDoc>;
119:  let clerk: ClerkApi;
120:  let fabricator: FabricatorApi;
121:  let spiderConfig: SpiderConfig = {};
123:  // ── Internal crawl operations ─────────────────────────────────────
125:  /**
126:   * Mark an engine failed and propagate failure to the rig (same update).
127:   */
128:  async function failEngine(
129:    rig: RigDoc,
130:    engineId: string,
131:    errorMessage: string,
132:  ): Promise<void> {
133:    const now = new Date().toISOString();
134:    const updatedEngines = rig.engines.map((e) => {
135:      if (e.id === engineId) {
136:        return { ...e, status: 'failed' as const, error: errorMessage, completedAt: now };
137:      }
138:      if (e.status === 'pending') {
139:        return { ...e, status: 'cancelled' as const };
140:      }
141:      return e;
142:    });
143:    await rigsBook.patch(rig.id, {
144:      engines: updatedEngines,
145:      status: 'failed',
146:    });
147:  }
149:  /**
150:   * Phase 1 — collect.
151:   *
152:   * Find the first running engine with a sessionId whose session has
153:   * reached a terminal state. Populate yields and advance the engine
154:   * (and possibly the rig) to completed or failed.
155:   */
156:  async function tryCollect(): Promise<CrawlResult | null> {
157:    const runningRigs = await rigsBook.find({ where: [['status', '=', 'running']] });
158:    for (const rig of runningRigs) {
159:      for (const engine of rig.engines) {
160:        if (engine.status !== 'running' || !engine.sessionId) continue;
162:        const session = await sessionsBook.get(engine.sessionId);
163:        if (!session || session.status === 'running') continue;
165:        // Terminal session found — collect.
166:        const now = new Date().toISOString();
168:        if (session.status === 'failed' || session.status === 'timeout') {
169:          await failEngine(rig, engine.id, session.error ?? `Session ${session.status}`);
170:          return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'failed' };
171:        }
173:        // Completed session — assemble yields via engine's collect() or generic default.
174:        const design = fabricator.getEngineDesign(engine.designId);
175:        let yields: unknown;
176:        if (design?.collect) {
177:          const givens = { ...engine.givensSpec };
178:          const upstream = buildUpstreamMap(rig);
179:          const context = { engineId: engine.id, upstream };
180:          yields = await design.collect(engine.sessionId!, givens, context);
181:        } else {
182:          yields = {
183:            sessionId: session.id,
184:            sessionStatus: session.status,
185:            ...(session.output !== undefined ? { output: session.output } : {}),
186:          };
187:        }
189:        if (!isJsonSerializable(yields)) {
190:          await failEngine(rig, engine.id, 'Session yields are not JSON-serializable');
191:          return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'failed' };
192:        }
194:        const updatedEngines = rig.engines.map((e) =>
195:          e.id === engine.id
196:            ? { ...e, status: 'completed' as const, yields, completedAt: now }
197:            : e,
198:        );
200:        const allCompleted = updatedEngines.every((e) => e.status === 'completed');
201:        await rigsBook.patch(rig.id, {
202:          engines: updatedEngines,
203:          status: allCompleted ? 'completed' : 'running',
204:        });
206:        if (allCompleted) {
207:          return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'completed' };
208:        }
209:        return { action: 'engine-completed', rigId: rig.id, engineId: engine.id };
210:      }
211:    }
212:    return null;
213:  }
215:  /**
216:   * Phase 2 — run.
217:   *
218:   * Find the first pending engine in any running rig whose upstream is
219:   * all completed. Execute it:
220:   * - Clockwork ('completed') → store yields, mark engine completed,
221:   *   check for rig completion.
222:   * - Quick ('launched') → store sessionId, mark engine running.
223:   */
224:  async function tryRun(): Promise<CrawlResult | null> {
225:    const runningRigs = await rigsBook.find({ where: [['status', '=', 'running']] });
226:    for (const rig of runningRigs) {
227:      const pending = findRunnableEngine(rig);
228:      if (!pending) continue;
230:      const design = fabricator.getEngineDesign(pending.designId);
231:      if (!design) {
232:        await failEngine(rig, pending.id, `No engine design found for "${pending.designId}"`);
233:        return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'failed' };
234:      }
236:      const now = new Date().toISOString();
237:      const upstream = buildUpstreamMap(rig);
238:      const givens = { ...pending.givensSpec };
239:      const context = { engineId: pending.id, upstream };
241:      let engineResult: Awaited<ReturnType<typeof design.run>>;
242:      try {
243:        // Mark engine as running before executing
244:        const startedEngines = rig.engines.map((e) =>
245:          e.id === pending.id ? { ...e, status: 'running' as const, startedAt: now } : e,
246:        );
247:        await rigsBook.patch(rig.id, { engines: startedEngines });
249:        // Re-fetch to get the up-to-date engines list (with startedAt set)
250:        const updatedRig = { ...rig, engines: startedEngines };
252:        engineResult = await design.run(givens, context);
254:        if (engineResult.status === 'launched') {
255:          // Quick engine — store sessionId, leave engine in 'running'
256:          const { sessionId } = engineResult;
257:          const launchedEngines = updatedRig.engines.map((e) =>
258:            e.id === pending.id
259:              ? { ...e, status: 'running' as const, sessionId }
260:              : e,
261:          );
262:          await rigsBook.patch(rig.id, { engines: launchedEngines });
263:          return { action: 'engine-started', rigId: rig.id, engineId: pending.id };
264:        }
266:        // Clockwork engine — validate and store yields
267:        const { yields } = engineResult;
268:        if (!isJsonSerializable(yields)) {
269:          await failEngine(updatedRig, pending.id, 'Engine yields are not JSON-serializable');
270:          return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'failed' };
271:        }
273:        const completedAt = new Date().toISOString();
274:        const completedEngines = updatedRig.engines.map((e) =>
275:          e.id === pending.id
276:            ? { ...e, status: 'completed' as const, yields, completedAt }
277:            : e,
278:        );
279:        const allCompleted = completedEngines.every((e) => e.status === 'completed');
280:        await rigsBook.patch(rig.id, {
281:          engines: completedEngines,
282:          status: allCompleted ? 'completed' : 'running',
283:        });
285:        if (allCompleted) {
286:          return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'completed' };
287:        }
288:        return { action: 'engine-completed', rigId: rig.id, engineId: pending.id };
289:      } catch (err) {
290:        const errorMessage = err instanceof Error ? err.message : String(err);
291:        await failEngine(rig, pending.id, errorMessage);
292:        return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'failed' };
293:      }
294:    }
295:    return null;
296:  }
298:  /**
299:   * Phase 3 — spawn.
300:   *
301:   * Find the oldest ready writ with no existing rig. Create a rig and
302:   * transition the writ to active so the Clerk tracks it as in-progress.
303:   */
304:  async function trySpawn(): Promise<CrawlResult | null> {
305:    // Find ready writs ordered by creation time (oldest first)
306:    const readyWrits = await writsBook.find({
307:      where: [['status', '=', 'ready']],
308:      orderBy: ['createdAt', 'asc'],
309:      limit: 10,
310:    });
312:    for (const writ of readyWrits) {
313:      // Check for existing rig
314:      const existing = await rigsBook.find({
315:        where: [['writId', '=', writ.id]],
316:        limit: 1,
317:      });
318:      if (existing.length > 0) continue;
320:      const rigId = generateId('rig', 4);
321:      const engines = buildStaticEngines(writ, spiderConfig);
323:      const rig: RigDoc = {
324:        id: rigId,
325:        writId: writ.id,
326:        status: 'running',
327:        engines,
328:        createdAt: new Date().toISOString(),
329:      };
331:      await rigsBook.put(rig);
333:      // Transition writ to active so Clerk tracks it
334:      try {
335:        await clerk.transition(writ.id, 'active');
336:      } catch (err) {
337:        // Only swallow state-transition conflicts (writ already moved past 'ready')
338:        if (err instanceof Error && err.message.includes('transition')) {
339:          // Race condition — another spider got here first. The rig is already created,
340:          // so we continue. The writ is already active or beyond.
341:        } else {
342:          throw err;
343:        }
344:      }
346:      return { action: 'rig-spawned', rigId, writId: writ.id };
347:    }
349:    return null;
350:  }
352:  // ── SpiderApi ─────────────────────────────────────────────────────
354:  const api: SpiderApi = {
355:    async crawl(): Promise<CrawlResult | null> {
356:      const collected = await tryCollect();
357:      if (collected) return collected;
359:      const ran = await tryRun();
360:      if (ran) return ran;
362:      const spawned = await trySpawn();
363:      if (spawned) return spawned;
365:      return null;
366:    },
368:    async show(id: string): Promise<RigDoc> {
369:      const results = await rigsBook.find({ where: [['id', '=', id]], limit: 1 });
370:      if (results.length === 0) {
371:        throw new Error(`Rig "${id}" not found.`);
372:      }
373:      return results[0];
374:    },
376:    async list(filters?: RigFilters): Promise<RigDoc[]> {
377:      const where: WhereClause = [];
378:      if (filters?.status !== undefined) {
379:        where.push(['status', '=', filters.status]);
380:      }
381:      const limit = filters?.limit ?? 20;
382:      return rigsBook.find({
383:        where,
384:        orderBy: ['createdAt', 'desc'],
385:        limit,
386:        ...(filters?.offset !== undefined ? { offset: filters.offset } : {}),
387:      });
388:    },
390:    async forWrit(writId: string): Promise<RigDoc | null> {
391:      const results = await rigsBook.find({ where: [['writId', '=', writId]], limit: 1 });
392:      return results[0] ?? null;
393:    },
394:  };
396:  // ── Apparatus ─────────────────────────────────────────────────────
398:  return {
399:    apparatus: {
400:      requires: ['stacks', 'clerk', 'fabricator'],
402:      supportKit: {
403:        books: {
404:          rigs: {
405:            indexes: ['status', 'writId', ['status', 'writId'], 'createdAt'],
406:          },
407:        },
408:        engines: {
409:          draft:     draftEngine,
410:          implement: implementEngine,
411:          review:    reviewEngine,
412:          revise:    reviseEngine,
413:          seal:      sealEngine,
414:        },
415:        tools: [crawlOneTool, crawlContinualTool, rigShowTool, rigListTool, rigForWritTool],
416:      },
418:      provides: api,
420:      start(_ctx: StartupContext): void {
421:        const g = guild();
422:        spiderConfig = g.guildConfig().spider ?? {};
424:        const stacks = g.apparatus<StacksApi>('stacks');
425:        clerk = g.apparatus<ClerkApi>('clerk');
426:        fabricator = g.apparatus<FabricatorApi>('fabricator');
428:        rigsBook = stacks.book<RigDoc>('spider', 'rigs');
429:        sessionsBook = stacks.readBook<SessionDoc>('animator', 'sessions');
430:        writsBook = stacks.readBook<WritDoc>('clerk', 'writs');
432:        // CDC — Phase 1 cascade on rigs book.
433:        // When a rig reaches a terminal state, transition the associated writ.
434:        stacks.watch<RigDoc>(
435:          'spider',
436:          'rigs',
437:          async (event) => {
438:            if (event.type !== 'update') return;
440:            const rig = event.entry;
441:            const prev = event.prev;
443:            // Only act when status changes to a terminal state
444:            if (rig.status === prev.status) return;
446:            if (rig.status === 'completed') {
447:              // Use seal yields as the resolution summary
448:              const sealEngine = rig.engines.find((e) => e.id === 'seal');
449:              const resolution = sealEngine?.yields
450:                ? JSON.stringify(sealEngine.yields)
451:                : 'Rig completed';
452:              await clerk.transition(rig.writId, 'completed', { resolution });
453:            } else if (rig.status === 'failed') {
454:              const failedEngine = rig.engines.find((e) => e.status === 'failed');
455:              const resolution = failedEngine?.error ?? 'Engine failure';
456:              await clerk.transition(rig.writId, 'failed', { resolution });
457:            }
458:          },
459:          { failOnError: true },
460:        );
461:      },
462:    },
463:  };
464:}

