1:/**
2: * The Spider — public types.
3: *
4: * Rig and engine data model, CrawlResult, SpiderApi, and configuration.
5: * Engine yield shapes (DraftYields, SealYields) live here too so downstream
6: * packages can import them without depending on the engine implementation files.
7: */
9:// ── Engine instance status ────────────────────────────────────────────
11:export type EngineStatus = 'pending' | 'running' | 'completed' | 'failed' | 'cancelled';
13:// ── Engine instance ───────────────────────────────────────────────────
15:/**
16: * A single engine slot within a rig.
17: *
18: * `id` is the engine's position identifier (e.g. 'draft', 'implement').
19: * For the static pipeline it matches `designId`.
20: *
21: * `givensSpec` holds literal values set at spawn time (writ, role, commands).
22: * The Spider assembles `givens` from this directly; upstream yields arrive
23: * via `context.upstream` as the escape hatch.
24: */
25:export interface EngineInstance {
26:  /** Unique identifier within the rig (e.g. 'draft', 'implement'). */
27:  id: string;
28:  /** The engine design to look up in the Fabricator. */
29:  designId: string;
30:  /** Current execution status. */
31:  status: EngineStatus;
32:  /** Engine IDs that must be completed before this engine can run. */
33:  upstream: string[];
34:  /** Literal givens values set at rig spawn time. */
35:  givensSpec: Record<string, unknown>;
36:  /** Yields from a completed engine run (JSON-serializable). */
37:  yields?: unknown;
38:  /** Error message if this engine failed. */
39:  error?: string;
40:  /** Session ID from a launched quick engine, used by the collect step. */
41:  sessionId?: string;
42:  /** ISO timestamp when execution started. */
43:  startedAt?: string;
44:  /** ISO timestamp when execution completed (or failed). */
45:  completedAt?: string;
46:}
48:// ── Rig ──────────────────────────────────────────────────────────────
50:export type RigStatus = 'running' | 'completed' | 'failed';
52:/**
53: * A rig — the execution context for a single writ.
54: *
55: * Stored in The Stacks (`spider/rigs` book). The `engines` array is the
56: * ordered pipeline of engine instances. The Spider updates this document
57: * in-place as engines run and complete.
58: */
59:export interface RigDoc {
60:  /** Index signature required to satisfy BookEntry constraint. */
61:  [key: string]: unknown;
62:  /** Unique rig id. */
63:  id: string;
64:  /** The writ this rig is executing. */
65:  writId: string;
66:  /** Current rig status. */
67:  status: RigStatus;
68:  /** Ordered engine pipeline. */
69:  engines: EngineInstance[];
70:  /** ISO timestamp when the rig was created. */
71:  createdAt: string;
72:}
74:// ── Rig filters ───────────────────────────────────────────────────────
76:/**
77: * Filters for listing rigs.
78: */
79:export interface RigFilters {
80:  /** Filter by rig status. */
81:  status?: RigStatus;
82:  /** Maximum number of results (default: 20). */
83:  limit?: number;
84:  /** Number of results to skip. */
85:  offset?: number;
86:}
88:// ── CrawlResult ────────────────────────────────────────────────────────
90:/**
91: * The result of a single crawl() call.
92: *
93: * Four variants, ordered by priority:
94: * - 'engine-completed' — an engine finished (collected or ran inline); rig still running
95: * - 'engine-started'   — launched a quick engine's session
96: * - 'rig-spawned'      — created a new rig for a ready writ
97: * - 'rig-completed'    — the crawl step caused a rig to reach a terminal state
98: *
99: * null means no work was available.
100: */
101:export type CrawlResult =
102:  | { action: 'engine-completed'; rigId: string; engineId: string }
103:  | { action: 'engine-started'; rigId: string; engineId: string }
104:  | { action: 'rig-spawned'; rigId: string; writId: string }
105:  | { action: 'rig-completed'; rigId: string; writId: string; outcome: 'completed' | 'failed' };
107:// ── SpiderApi ─────────────────────────────────────────────────────────
109:/**
110: * The Spider's public API — retrieved via guild().apparatus<SpiderApi>('spider').
111: */
112:export interface SpiderApi {
113:  /**
114:   * Execute one step of the crawl loop.
115:   *
116:   * Priority ordering: collect > run > spawn.
117:   * Returns null when no work is available.
118:   */
119:  crawl(): Promise<CrawlResult | null>;
121:  /**
122:   * Show a rig by id. Throws if not found.
123:   */
124:  show(id: string): Promise<RigDoc>;
126:  /**
127:   * List rigs with optional filters, ordered by createdAt descending.
128:   */
129:  list(filters?: RigFilters): Promise<RigDoc[]>;
131:  /**
132:   * Find the rig for a given writ. Returns null if no rig exists.
133:   */
134:  forWrit(writId: string): Promise<RigDoc | null>;
135:}
137:// ── Configuration ─────────────────────────────────────────────────────
139:/**
140: * Spider apparatus configuration — lives under the `spider` key in guild.json.
141: */
142:export interface SpiderConfig {
143:  /**
144:   * Role to summon for quick engine sessions.
145:   * Default: 'artificer'.
146:   */
147:  role?: string;
148:  /**
149:   * Polling interval for crawlContinual tool (milliseconds).
150:   * Default: 5000.
151:   */
152:  pollIntervalMs?: number;
153:  /**
154:   * Build command to pass to quick engines.
155:   */
156:  buildCommand?: string;
157:  /**
158:   * Test command to pass to quick engines.
159:   */
160:  testCommand?: string;
161:}
163:// ── Engine yield shapes ───────────────────────────────────────────────
165:/**
166: * Yields from the `draft` clockwork engine.
167: * The Spider stores these in the engine instance and passes them
168: * to downstream engines via context.upstream['draft'].
169: */
170:export interface DraftYields {
171:  /** The draft's unique id. */
172:  draftId: string;
173:  /** Codex this draft belongs to. */
174:  codexName: string;
175:  /** Git branch name for the draft. */
176:  branch: string;
177:  /** Absolute filesystem path to the draft's worktree. */
178:  path: string;
179:  /** HEAD commit SHA at the time the draft was opened. Used by review engine to compute diffs. */
180:  baseSha: string;
181:}
183:/**
184: * Yields from the `seal` clockwork engine.
185: */
186:export interface SealYields {
187:  /** The commit SHA at head of the target branch after sealing. */
188:  sealedCommit: string;
189:  /** Git strategy used. */
190:  strategy: 'fast-forward' | 'rebase';
191:  /** Number of retry attempts. */
192:  retries: number;
193:  /** Number of inscriptions (commits) sealed. */
194:  inscriptionsSealed: number;
195:}
197:/**
198: * Yields from the `implement` quick engine.
199: * Set by the Spider's collect step when the Animator session completes.
200: */
201:export interface ImplementYields {
202:  /** The Animator session id. */
203:  sessionId: string;
204:  /** Terminal status of the session. */
205:  sessionStatus: 'completed' | 'failed';
206:}
208:/**
209: * A single mechanical check (build or test) run by the review engine
210: * before launching the reviewer session.
211: */
212:export interface MechanicalCheck {
213:  /** Check name. */
214:  name: 'build' | 'test';
215:  /** Whether the command exited with code 0. */
216:  passed: boolean;
217:  /** Combined stdout+stderr, truncated to 4KB. */
218:  output: string;
219:  /** Wall-clock duration of the check in milliseconds. */
220:  durationMs: number;
221:}
223:/**
224: * Yields from the `review` quick engine.
225: * Assembled by the Spider's collect step from session.output and session.metadata.
226: */
227:export interface ReviewYields {
228:  /** The Animator session id. */
229:  sessionId: string;
230:  /** Reviewer's overall assessment — true if the review passed. */
231:  passed: boolean;
232:  /** Structured markdown findings from the reviewer's final message. */
233:  findings: string;
234:  /** Mechanical check results run before the reviewer session. */
235:  mechanicalChecks: MechanicalCheck[];
236:}
238:/**
239: * Yields from the `revise` quick engine.
240: * Set by the Spider's collect step when the Animator session completes.
241: */
242:export interface ReviseYields {
243:  /** The Animator session id. */
244:  sessionId: string;
245:  /** Terminal status of the session. */
246:  sessionStatus: 'completed' | 'failed';
247:}
