1:/**
2: * The Fabricator — guild engine design registry apparatus.
3: *
4: * Scans installed engine designs from kit contributions and apparatus supportKits,
5: * and serves them to the Spider on demand.
6: *
7: * The Fabricator does not execute engines. It is a pure query service:
8: * designs in, designs out.
9: */
11:import type {
12:  StartupContext,
13:  LoadedPlugin,
14:  LoadedApparatus,
15:  Plugin,
16:} from '@shardworks/nexus-core';
17:import {
18:  guild,
19:  isLoadedKit,
20:  isLoadedApparatus,
21:} from '@shardworks/nexus-core';
23:// ── Public types ──────────────────────────────────────────────────────
25:/** Minimal execution context passed to an engine's run() method. */
26:export interface EngineRunContext {
27:  /** Simple string identity for this engine instance (e.g. 'draft', 'implement'). */
28:  engineId: string;
29:  /** All upstream yields, keyed by engine id. Escape hatch for engines that need to inspect the full upstream chain. */
30:  upstream: Record<string, unknown>;
31:}
33:/**
34: * The result of an engine run.
35: *
36: * 'completed' — synchronous work done inline, yields are available immediately.
37: * 'launched'  — async work launched in a session; the Spider polls for completion.
38: */
39:export type EngineRunResult =
40:  | { status: 'completed'; yields: unknown }
41:  | { status: 'launched'; sessionId: string };
43:/**
44: * An engine design — the unit of work the Fabricator catalogues and the
45: * Spider executes. Kit authors import this type from @shardworks/fabricator-apparatus.
46: */
47:export interface EngineDesign {
48:  /** Unique identifier for this engine design (e.g. 'draft', 'implement', 'review'). */
49:  id: string;
51:  /**
52:   * Execute this engine.
53:   *
54:   * @param givens   — the engine's declared inputs, assembled by the Spider.
55:   * @param context  — minimal execution context: engine id and upstream yields.
56:   */
57:  run(givens: Record<string, unknown>, context: EngineRunContext): Promise<EngineRunResult>;
59:  /**
60:   * Assemble yields from a completed session.
61:   *
62:   * Called by the Spider's collect step when a quick engine's session
63:   * reaches a terminal state. The engine looks up whatever it needs
64:   * via guild() — same dependency pattern as run().
65:   *
66:   * @param sessionId — the session to collect yields from (primary input).
67:   * @param givens    — same givens that were passed to run().
68:   * @param context   — same execution context that was passed to run().
69:   *
70:   * If not defined, the Spider uses a generic default:
71:   *   { sessionId, sessionStatus, output? }
72:   *
73:   * Only relevant for quick engines (those that return { status: 'launched' }).
74:   * Clockwork engines return yields directly from run().
75:   */
76:  collect?(sessionId: string, givens: Record<string, unknown>, context: EngineRunContext): Promise<unknown>;
77:}
79:/** The Fabricator's public API, exposed via `provides`. */
80:export interface FabricatorApi {
81:  /**
82:   * Look up an engine design by ID.
83:   * Returns the design if registered, undefined otherwise.
84:   */
85:  getEngineDesign(id: string): EngineDesign | undefined;
86:}
88:// ── Type guard ────────────────────────────────────────────────────────
90:/** Narrow an unknown value to EngineDesign. */
91:function isEngineDesign(value: unknown): value is EngineDesign {
92:  return (
93:    typeof value === 'object' &&
94:    value !== null &&
95:    typeof (value as Record<string, unknown>).id === 'string' &&
96:    typeof (value as Record<string, unknown>).run === 'function'
97:  );
98:}
100:// ── Implementation ────────────────────────────────────────────────────
102:/** The engine design registry — populated at startup, queried at runtime. */
103:class EngineRegistry {
104:  private readonly designs = new Map<string, EngineDesign>();
106:  /** Register all engine designs from a loaded plugin. */
107:  register(plugin: LoadedPlugin): void {
108:    if (isLoadedKit(plugin)) {
109:      this.registerFromKit(plugin.kit);
110:    } else if (isLoadedApparatus(plugin)) {
111:      if (plugin.apparatus.supportKit) {
112:        this.registerFromKit(plugin.apparatus.supportKit);
113:      }
114:    }
115:  }
117:  /** Extract and register engine designs from a kit (or supportKit) contribution. */
118:  private registerFromKit(kit: Record<string, unknown>): void {
119:    const rawEngines = kit.engines;
120:    if (typeof rawEngines !== 'object' || rawEngines === null) return;
122:    for (const value of Object.values(rawEngines as Record<string, unknown>)) {
123:      if (isEngineDesign(value)) {
124:        this.designs.set(value.id, value);
125:      }
126:    }
127:  }
129:  /** Look up an engine design by ID. */
130:  get(id: string): EngineDesign | undefined {
131:    return this.designs.get(id);
132:  }
133:}
135:// ── Apparatus factory ─────────────────────────────────────────────────
137:/**
138: * Create the Fabricator apparatus plugin.
139: *
140: * Returns a Plugin with:
141: * - `consumes: ['engines']` — scans kit/supportKit contributions
142: * - `provides: FabricatorApi` — the engine design registry API
143: */
144:export function createFabricator(): Plugin {
145:  const registry = new EngineRegistry();
147:  const api: FabricatorApi = {
148:    getEngineDesign(id: string): EngineDesign | undefined {
149:      return registry.get(id);
150:    },
151:  };
153:  return {
154:    apparatus: {
155:      requires: [],
156:      consumes: ['engines'],
157:      provides: api,
159:      start(ctx: StartupContext): void {
160:        const g = guild();
162:        // Scan all already-loaded kits. These fired plugin:initialized before
163:        // any apparatus started, so we can't catch them via events.
164:        for (const kit of g.kits()) {
165:          registry.register(kit);
166:        }
168:        // Subscribe to plugin:initialized for apparatus supportKits that
169:        // fire after us in the startup sequence.
170:        ctx.on('plugin:initialized', (plugin: unknown) => {
171:          const loaded = plugin as LoadedPlugin;
172:          // Skip kits — we already scanned them above.
173:          if (isLoadedApparatus(loaded)) {
174:            registry.register(loaded);
175:          }
176:        });
177:      },
178:    },
179:  };
180:}

