33:/**
34: * Build a minimal StartupContext that captures and fires events.
35: */
36:function buildCtx(): {
37:  ctx: StartupContext;
38:  fire: (event: string, ...args: unknown[]) => Promise<void>;
39:} {
40:  const handlers = new Map<string, Array<(...args: unknown[]) => void | Promise<void>>>();
41:  const ctx: StartupContext = {
42:    on(event, handler) {
43:      const list = handlers.get(event) ?? [];
44:      list.push(handler);
45:      handlers.set(event, list);
46:    },
47:  };
48:  async function fire(event: string, ...args: unknown[]): Promise<void> {
49:    for (const h of handlers.get(event) ?? []) {
50:      await h(...args);
51:    }
52:  }
53:  return { ctx, fire };
54:}
