1:/**
2: * Arbor — the guild runtime.
3: *
4: * `createGuild()` is the single entry point. It reads guild.json, loads all
5: * declared plugins, validates dependencies, starts apparatus in order, wires
6: * the guild() singleton, and returns the Guild object.
7: *
8: * The full plugin lifecycle:
9: *   1. Load    — imports all declared plugin packages, discriminates kit vs apparatus
10: *   2. Validate — checks `requires` declarations, detects circular dependencies
11: *   3. Start   — calls start(ctx) on each apparatus in dependency-resolved order
12: *   4. Events  — fires `plugin:initialized` after each plugin loads
13: *   5. Warn    — advisory warnings for mismatched kit contributions / recommends
14: *
15: * Pure logic (validation, ordering, events) lives in guild-lifecycle.ts.
16: * This file handles I/O and orchestration.
17: */
19:import {
20:  readGuildConfig,
21:  writeGuildConfig,
22:  findGuildRoot,
23:  isKit,
24:  isApparatus,
25:  setGuild,
26:  resolveGuildPackageEntry,
27:  resolvePackageNameForPluginId,
28:  readGuildPackageJson,
29:} from '@shardworks/nexus-core';
30:import type {
31:  Guild,
32:  LoadedKit,
33:  LoadedApparatus,
34:} from '@shardworks/nexus-core';
36:import {
37:  validateRequires,
38:  topoSort,
39:  collectStartupWarnings,
40:  buildStartupContext,
41:  fireEvent,
42:} from './guild-lifecycle.ts';
43:import type { EventHandlerMap } from './guild-lifecycle.ts';
45:// ── Public API ────────────────────────────────────────────────────────
47:/**
48: * Create and start a guild.
49: *
50: * Reads guild.json, loads all declared plugins, validates dependencies,
51: * starts apparatus in dependency order, and returns the Guild object.
52: * Also sets the guild() singleton so apparatus code can access it.
53: *
54: * @param root - Absolute path to the guild root. Defaults to auto-detection
55: *               by walking up from cwd until guild.json is found.
56: * @returns The initialized Guild — the same object guild() returns.
57: */
58:export async function createGuild(root?: string): Promise<Guild> {
59:  const guildRoot = root ?? findGuildRoot();
60:  const config = readGuildConfig(guildRoot);
62:  const kits:        LoadedKit[]        = [];
63:  const apparatuses: LoadedApparatus[]  = [];
64:  const eventHandlers: EventHandlerMap = new Map();
66:  // ── Load phase ─────────────────────────────────────────────────────
68:  for (const pluginId of config.plugins) {
69:    const packageName = resolvePackageNameForPluginId(guildRoot, pluginId);
70:    if (!packageName) {
71:      console.warn(`[arbor] No package found in package.json for plugin "${pluginId}" — skipping`);
72:      continue;
73:    }
75:    const { version } = readGuildPackageJson(guildRoot, packageName);
77:    try {
78:      const entryPath = resolveGuildPackageEntry(guildRoot, packageName);
79:      const mod = await import(entryPath) as { default: unknown };
80:      const raw = mod.default;
82:      if (isApparatus(raw)) {
83:        apparatuses.push({ packageName, id: pluginId, version, apparatus: raw.apparatus });
84:      } else if (isKit(raw)) {
85:        kits.push({ packageName, id: pluginId, version, kit: raw.kit });
86:      } else {
87:        console.warn(
88:          `[arbor] Plugin "${packageName}" does not export a kit or apparatus — skipping. ` +
89:          `Plugins must export { kit: ... } or { apparatus: ... }.`,
90:        );
91:      }
92:    } catch (err) {
93:      const message = err instanceof Error ? err.message : String(err);
94:      console.warn(`[arbor] Failed to load plugin "${packageName}": ${message}`);
95:    }
96:  }
98:  // ── Validation phase ───────────────────────────────────────────────
100:  validateRequires(kits, apparatuses);
102:  // ── Startup warnings ───────────────────────────────────────────────
104:  for (const warning of collectStartupWarnings(kits, apparatuses)) {
105:    console.warn(warning);
106:  }
108:  // ── Start phase ────────────────────────────────────────────────────
110:  const orderedApparatuses = topoSort(apparatuses);
111:  const provides = new Map<string, unknown>();
113:  // Wire guild singleton before any apparatus starts so start() methods
114:  // can call guild(). The provides Map is populated progressively as each
115:  // apparatus starts; dependency ordering guarantees declared deps are
116:  // available.
118:  const guildInstance: Guild = {
119:    home: guildRoot,
121:    apparatus<T>(name: string): T {
122:      const p = provides.get(name);
123:      if (p === undefined) {
124:        throw new Error(
125:          `[guild] apparatus("${name}") is not available. ` +
126:          `No loaded apparatus provides this id. Check guild.json plugins list.`,
127:        );
128:      }
129:      return p as T;
130:    },
132:    config<T = Record<string, unknown>>(pluginId: string): T {
133:      // GuildConfig types only the framework-level keys (name, nexus, plugins, etc.).
134:      // Plugin-specific config sections (e.g. "animator", "stacks") are additional
135:      // top-level keys in guild.json that GuildConfig doesn't model. The cast is safe
136:      // because guild.json is a plain JSON object — all keys are accessible at runtime.
137:      // Plugins can use module augmentation on GuildConfig to get typed access; this
138:      // generic path remains the untyped fallback.
139:      const cfg = config as unknown as Record<string, unknown>;
140:      return (cfg[pluginId] ?? {}) as T;
141:    },
143:    writeConfig<T = Record<string, unknown>>(pluginId: string, value: T): void {
144:      // Update the in-memory config so subsequent reads reflect the change,
145:      // then persist to disk. The cast is the same pattern as config() above.
146:      const cfg = config as unknown as Record<string, unknown>;
147:      cfg[pluginId] = value;
148:      writeGuildConfig(guildRoot, config);
149:    },
151:    guildConfig() {
152:      return config;
153:    },
155:    kits()        { return [...kits]; },
156:    apparatuses() { return [...orderedApparatuses]; },
157:  };
158:  setGuild(guildInstance);
160:  // Fire plugin:initialized for all kits before starting any apparatus
161:  for (const kit of kits) {
162:    await fireEvent(eventHandlers, 'plugin:initialized', kit);
163:  }
165:  // Start each apparatus in dependency order
166:  const startupCtx = buildStartupContext(eventHandlers);
167:  for (const app of orderedApparatuses) {
168:    // Register provides before start() so apparatuses with eager provides are
169:    // visible to later startups that run during this loop.
170:    if (app.apparatus.provides !== undefined) {
171:      provides.set(app.id, app.apparatus.provides);
172:    }
174:    await app.apparatus.start(startupCtx);
176:    // Re-check after start() for deferred provides (e.g. Stacks uses a getter
177:    // that returns undefined until start() populates the backing variable).
178:    if (!provides.has(app.id) && app.apparatus.provides !== undefined) {
179:      provides.set(app.id, app.apparatus.provides);
180:    }
182:    await fireEvent(eventHandlers, 'plugin:initialized', app);
183:  }
185:  return guildInstance;
186:}

