1:/**
2: * Draft engine — clockwork.
3: *
4: * Opens a draft binding via the Scriptorium. Returns DraftYields
5: * containing the worktree path and branch name for downstream engines.
6: */
8:import { execSync } from 'node:child_process';
9:import { guild } from '@shardworks/nexus-core';
10:import type { EngineDesign } from '@shardworks/fabricator-apparatus';
11:import type { ScriptoriumApi } from '@shardworks/codexes-apparatus';
12:import type { WritDoc } from '@shardworks/clerk-apparatus';
13:import type { DraftYields } from '../types.ts';
15:const draftEngine: EngineDesign = {
16:  id: 'draft',
18:  async run(givens, _context) {
19:    const scriptorium = guild().apparatus<ScriptoriumApi>('codexes');
20:    const writ = givens.writ as WritDoc;
22:    if (!writ.codex) {
23:      throw new Error(
24:        `Writ "${writ.id}" has no codex — cannot open a draft binding.`,
25:      );
26:    }
28:    const draft = await scriptorium.openDraft({
29:      codexName: writ.codex,
30:      associatedWith: writ.id,
31:    });
33:    let baseSha: string;
34:    try {
35:      baseSha = execSync('git rev-parse HEAD', { cwd: draft.path, encoding: 'utf-8' }).trim();
36:    } catch (err) {
37:      throw new Error(
38:        `Failed to read HEAD commit in draft worktree "${draft.path}": ${(err as Error).message}`,
39:      );
40:    }
42:    const yields: DraftYields = {
43:      draftId: draft.id,
44:      codexName: draft.codexName,
45:      branch: draft.branch,
46:      path: draft.path,
47:      baseSha,
48:    };
50:    return { status: 'completed', yields };
51:  },
52:};
54:export default draftEngine;

