1:/**
2: * Review engine — quick (Animator-backed).
3: *
4: * Runs mechanical checks (build/test) synchronously in the draft worktree,
5: * then summons a reviewer anima to assess the implementation against the spec.
6: * Returns `{ status: 'launched', sessionId }` so the Spider's collect step
7: * can call this engine's collect() method on subsequent crawls.
8: *
9: * Collect method:
10: *   - Reads session.output as the reviewer's structured markdown findings
11: *   - Parses `passed` from /^###\s*Overall:\s*PASS/mi
12: *   - Retrieves mechanicalChecks from session.metadata
13: */
15:import { execFile } from 'node:child_process';
16:import { promisify } from 'node:util';
17:import { guild } from '@shardworks/nexus-core';
18:import type { EngineDesign } from '@shardworks/fabricator-apparatus';
19:import type { AnimatorApi, SessionDoc } from '@shardworks/animator-apparatus';
20:import type { StacksApi } from '@shardworks/stacks-apparatus';
21:import type { WritDoc } from '@shardworks/clerk-apparatus';
22:import type { DraftYields, MechanicalCheck, ReviewYields } from '../types.ts';
24:const execFileAsync = promisify(execFile);
26:async function runCheck(name: 'build' | 'test', command: string, cwd: string): Promise<MechanicalCheck> {
27:  const start = Date.now();
28:  try {
29:    const { stdout, stderr } = await execFileAsync('sh', ['-c', command], { cwd });
30:    const output = (stdout + stderr).slice(0, 4096);
31:    return { name, passed: true, output, durationMs: Date.now() - start };
32:  } catch (err: unknown) {
33:    const execErr = err as { stdout?: string; stderr?: string };
34:    const output = ((execErr.stdout ?? '') + (execErr.stderr ?? '')).slice(0, 4096);
35:    return { name, passed: false, output, durationMs: Date.now() - start };
36:  }
37:}
39:async function gitDiff(cwd: string, baseSha: string): Promise<string> {
40:  try {
41:    const { stdout } = await execFileAsync('git', ['diff', `${baseSha}..HEAD`], { cwd });
42:    return stdout;
43:  } catch {
44:    return '';
45:  }
46:}
48:async function gitStatus(cwd: string): Promise<string> {
49:  try {
50:    const { stdout } = await execFileAsync('git', ['status', '--porcelain'], { cwd });
51:    return stdout;
52:  } catch {
53:    return '';
54:  }
55:}
57:function assembleReviewPrompt(writ: WritDoc, diff: string, status: string, checks: MechanicalCheck[]): string {
58:  const checksSection = checks.length === 0
59:    ? '(No mechanical checks configured.)'
60:    : checks.map((c) => `### ${c.name}: ${c.passed ? 'PASSED' : 'FAILED'}\n\`\`\`\n${c.output}\n\`\`\``).join('\n\n');
62:  return `# Code Review
64:You are reviewing work on a commission. Your job is to assess whether the
65:implementation satisfies the spec, identify any gaps or problems, and produce
66:a structured findings document.
68:## The Commission (Spec)
70:${writ.body}
72:## Implementation Diff
74:Changes since the draft was opened:
76:\`\`\`diff
77:${diff}
78:\`\`\`
80:## Current Worktree State
82:\`\`\`
83:${status}
84:\`\`\`
86:## Mechanical Check Results
88:${checksSection}
90:## Instructions
92:Assess the implementation against the spec. Produce your findings in this format:
94:### Overall: PASS or FAIL
96:### Completeness
97:- Which spec requirements are addressed?
98:- Which are missing or partially addressed?
100:### Correctness
101:- Are there bugs, logic errors, or regressions?
102:- Do the tests pass? If not, what fails?
104:### Quality
105:- Code style consistent with the codebase?
106:- Appropriate test coverage for new code?
107:- Any concerns about the approach?
109:### Required Changes (if FAIL)
110:Numbered list of specific changes needed, in priority order.
112:Produce your findings as your final message in the format above.`;
113:}
115:const reviewEngine: EngineDesign = {
116:  id: 'review',
118:  async run(givens, context) {
119:    const animator = guild().apparatus<AnimatorApi>('animator');
120:    const writ = givens.writ as WritDoc;
121:    const draft = context.upstream['draft'] as DraftYields;
123:    // 1. Run mechanical checks synchronously before the reviewer session
124:    const checks: MechanicalCheck[] = [];
125:    if (givens.buildCommand) {
126:      checks.push(await runCheck('build', givens.buildCommand as string, draft.path));
127:    }
128:    if (givens.testCommand) {
129:      checks.push(await runCheck('test', givens.testCommand as string, draft.path));
130:    }
132:    // 2. Compute diff since draft opened and current worktree state
133:    const diff = await gitDiff(draft.path, draft.baseSha);
134:    const status = await gitStatus(draft.path);
136:    // 3. Assemble review prompt
137:    const prompt = assembleReviewPrompt(writ, diff, status, checks);
139:    // 4. Launch reviewer session — stash mechanicalChecks in metadata for collect step
140:    const handle = animator.summon({
141:      role: givens.role as string,
142:      prompt,
143:      cwd: draft.path,
144:      metadata: {
145:        engineId: context.engineId,
146:        writId: writ.id,
147:        mechanicalChecks: checks,
148:      },
149:    });
151:    return { status: 'launched', sessionId: handle.sessionId };
152:  },
154:  async collect(sessionId: string): Promise<ReviewYields> {
155:    const stacks = guild().apparatus<StacksApi>('stacks');
156:    const sessionsBook = stacks.readBook<SessionDoc>('animator', 'sessions');
157:    const session = await sessionsBook.get(sessionId);
158:    const findings = session?.output ?? '';
159:    const passed = /^###\s*Overall:\s*PASS/mi.test(findings);
160:    const mechanicalChecks = (session?.metadata?.mechanicalChecks as MechanicalCheck[]) ?? [];
161:    return { sessionId, passed, findings, mechanicalChecks };
162:  },
163:};
165:export default reviewEngine;

