1:/**
2: * Guild lifecycle — pure logic for plugin validation, ordering, and events.
3: *
4: * All functions here operate on in-memory data structures (LoadedKit[],
5: * LoadedApparatus[], Maps) with no I/O. This makes them independently
6: * testable with synthetic fixtures.
7: *
8: * `createGuild()` in arbor.ts is the orchestrator that performs I/O
9: * (config reading, dynamic imports) then delegates to these functions.
10: */
12:import type {
13:  StartupContext,
14:  LoadedKit,
15:  LoadedApparatus,
16:} from '@shardworks/nexus-core';
18:// ── Types ────────────────────────────────────────────────────────────
20:export type EventHandlerMap = Map<
21:  string,
22:  Array<(...args: unknown[]) => void | Promise<void>>
23:>;
25:// ── Validation ───────────────────────────────────────────────────────
27:/**
28: * Validate all `requires` declarations and detect circular dependencies.
29: * Throws with a descriptive error on the first problem found.
30: *
31: * Checks:
32: * - Apparatus requires: every named dependency must exist (kit or apparatus).
33: * - Kit requires: every named dependency must be an apparatus (kits can't
34: *   depend on kits).
35: * - Cycle detection: no circular dependency chains among apparatuses.
36: */
37:export function validateRequires(
38:  kits: LoadedKit[],
39:  apparatuses: LoadedApparatus[],
40:): void {
41:  const apparatusIds = new Set(apparatuses.map((a) => a.id));
42:  const allIds = new Set([
43:    ...kits.map((k) => k.id),
44:    ...apparatuses.map((a) => a.id),
45:  ]);
47:  // Check apparatus requires
48:  for (const app of apparatuses) {
49:    for (const dep of app.apparatus.requires ?? []) {
50:      if (!allIds.has(dep)) {
51:        throw new Error(
52:          `[arbor] "${app.id}" requires "${dep}", which is not installed.`,
53:        );
54:      }
55:    }
56:  }
58:  // Check kit requires (must be apparatus names — kits can't depend on kits)
59:  for (const kit of kits) {
60:    for (const dep of kit.kit.requires ?? []) {
61:      if (!apparatusIds.has(dep)) {
62:        if (!allIds.has(dep)) {
63:          throw new Error(
64:            `[arbor] kit "${kit.id}" requires "${dep}", which is not installed.`,
65:          );
66:        }
67:        throw new Error(
68:          `[arbor] kit "${kit.id}" requires "${dep}", but that plugin is a kit, not an apparatus. ` +
69:          `Kit requires must name apparatus plugins.`,
70:        );
71:      }
72:    }
73:  }
75:  // Detect circular dependencies among apparatuses
76:  const visiting = new Set<string>();
77:  const visited = new Set<string>();
79:  function visit(id: string, chain: string[]): void {
80:    if (visited.has(id)) return;
81:    if (visiting.has(id)) {
82:      const cycle = [...chain, id].join(' → ');
83:      throw new Error(`[arbor] Circular dependency detected: ${cycle}`);
84:    }
85:    visiting.add(id);
86:    const app = apparatuses.find((a) => a.id === id);
87:    if (app) {
88:      for (const dep of app.apparatus.requires ?? []) {
89:        visit(dep, [...chain, id]);
90:      }
91:    }
92:    visiting.delete(id);
93:    visited.add(id);
94:  }
96:  for (const app of apparatuses) {
97:    visit(app.id, []);
98:  }
99:}
101:// ── Dependency ordering ──────────────────────────────────────────────
103:/**
104: * Sort apparatuses in dependency-resolved order using topological sort.
105: * validateRequires() must be called first to ensure the graph is acyclic.
106: */
107:export function topoSort(apparatuses: LoadedApparatus[]): LoadedApparatus[] {
108:  const sorted: LoadedApparatus[] = [];
109:  const visited = new Set<string>();
111:  function visit(id: string): void {
112:    if (visited.has(id)) return;
113:    const app = apparatuses.find((a) => a.id === id);
114:    if (!app) return;
115:    for (const dep of app.apparatus.requires ?? []) {
116:      visit(dep);
117:    }
118:    visited.add(id);
119:    sorted.push(app);
120:  }
122:  for (const app of apparatuses) {
123:    visit(app.id);
124:  }
126:  return sorted;
127:}
129:// ── Startup warnings ─────────────────────────────────────────────────
131:/**
132: * Collect advisory warnings for kit contributions that no apparatus
133: * consumes, and for missing recommended apparatuses.
134: *
135: * Returns an array of warning strings. The caller decides how to emit
136: * them (console.warn, logger, etc.).
137: */
138:export function collectStartupWarnings(
139:  kits:        LoadedKit[],
140:  apparatuses: LoadedApparatus[],
141:): string[] {
142:  const warnings: string[] = [];
143:  const consumedTypes = new Set<string>();
144:  const installedIds  = new Set(apparatuses.map((a) => a.id));
146:  for (const app of apparatuses) {
147:    for (const token of app.apparatus.consumes ?? []) {
148:      consumedTypes.add(token);
149:    }
150:  }
152:  // Check apparatus recommends
153:  for (const app of apparatuses) {
154:    for (const rec of app.apparatus.recommends ?? []) {
155:      if (!installedIds.has(rec)) {
156:        warnings.push(
157:          `[arbor] warn: "${app.id}" recommends "${rec}" but it is not installed.`,
158:        );
159:      }
160:    }
161:  }
163:  for (const kit of kits) {
164:    // Check kit recommends
165:    for (const rec of kit.kit.recommends ?? []) {
166:      if (!installedIds.has(rec)) {
167:        warnings.push(
168:          `[arbor] warn: "${kit.id}" recommends "${rec}" but it is not installed.`,
169:        );
170:      }
171:    }
173:    // Check contribution types against consumes
174:    for (const key of Object.keys(kit.kit)) {
175:      if (key === 'requires' || key === 'recommends') continue;
176:      if (!consumedTypes.has(key)) {
177:        warnings.push(
178:          `[arbor] warn: "${kit.id}" contributes "${key}" but no installed apparatus declares consumes: ["${key}"]`,
179:        );
180:      }
181:    }
182:  }
184:  return warnings;
185:}
187:// ── Event system ─────────────────────────────────────────────────────
189:/**
190: * Build a StartupContext for an apparatus's start() call.
191: * The context provides event subscription; handlers are stored in the
192: * shared eventHandlers map so fireEvent can invoke them later.
193: */
194:export function buildStartupContext(
195:  eventHandlers: EventHandlerMap,
196:): StartupContext {
197:  return {
198:    on(event: string, handler: (...args: unknown[]) => void | Promise<void>) {
199:      const list = eventHandlers.get(event) ?? [];
200:      list.push(handler);
201:      eventHandlers.set(event, list);
202:    },
203:  };
204:}
206:/**
207: * Fire a lifecycle event, awaiting each handler sequentially.
208: */
209:export async function fireEvent(
210:  eventHandlers: EventHandlerMap,
211:  event:         string,
212:  ...args: unknown[]
213:): Promise<void> {
214:  const handlers = eventHandlers.get(event) ?? [];
215:  for (const h of handlers) {
216:    await h(...args);
217:  }
218:}

