  sessionsBook = stacks.readBook<SessionDoc>('animator', 'sessions');
  writsBook = stacks.readBook<WritDoc>('clerk', 'writs');

  // CDC — Phase 1 cascade on rigs book.
  stacks.watch<RigDoc>(
    'spider',
    'rigs',
    async (event) => {
